// Unit 2: The Software Development Life Cycle (Chapter 2, pp.29–58)
EXTRA_UNITS.push({
id:2, concepts:[
{title:"🎯 Learning Objectives",ref:"Module 2",content:`<p>By the end of this chapter you should be able to:</p><ul><li>Recognize that information system projects follow a well-defined <strong>SDLC methodology</strong></li><li>Examine the <strong>data and process models</strong> in an SDLC</li><li>Identify the more popular SDLC methodologies (Waterfall, Prototyping, RAD, PDM, Agile)</li><li>List the key features of the <strong>Phased Development Methodology (PDM)</strong></li><li>Identify <strong>where software testing occurs</strong> in the PDM</li></ul><div class="zh-note">本章目标：理解 SDLC 概念 · 数据/流程模型 · 5 种流行的 SDLC 方法 · PDM 的核心特性 · 测试在 PDM 中的位置。</div>`},
{title:"🏗️ Methodology vs Tools",ref:"pp.29–30",content:`<p>Two foundational concepts that students often confuse.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:10px;text-align:left;color:var(--accent-dim);">📘 Methodology</th><th style="padding:10px;text-align:left;color:var(--accent-dim);">🔧 Tool</th></tr></thead><tbody><tr><td style="padding:8px 10px;border-bottom:1px solid var(--border-light);"><strong>Recommended way</strong> of doing something</td><td style="padding:8px 10px;border-bottom:1px solid var(--border-light);"><strong>Device</strong> for accomplishing a task</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px 10px;">Organizes work, defines team operations</td><td style="padding:8px 10px;">Executes the actual technical work</td></tr><tr><td style="padding:8px 10px;font-style:italic;">🏠 Architect's blueprint (how to build)</td><td style="padding:8px 10px;font-style:italic;">🔨 Nail gun, circular saw, drill (what to build with)</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px 10px;font-style:italic;">💻 PDM, Agile, Waterfall</td><td style="padding:8px 10px;font-style:italic;">💻 Jira, GitHub, VS Code, Selenium</td></tr></tbody></table><div class="callout"><strong>Key:</strong> An SDLC is a <span class="key-term">methodology</span>. A <span class="key-term">stage</span> is a segment of an SDLC with specific activities. Tools support stages but don't define them.</div><div class="zh-note">方法论 = 怎么做的蓝图（PDM/Agile）。工具 = 用什么来做（Jira/GitHub/Selenium）。SDLC 是方法论。</div>`},
{title:"🌊 SDLC Evolution: 5 Approaches Compared",ref:"pp.30–33 + Module 2",content:`<p>Five SDLC families exist. Each solves a different problem.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Method</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Flexibility</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Time</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Best for</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">📋 Waterfall</td><td style="padding:6px 8px;">⛔ Very Low</td><td style="padding:6px 8px;">Long (years)</td><td style="padding:6px 8px;">Stable, well-known requirements</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">🔄 Prototyping</td><td style="padding:6px 8px;">✅ High</td><td style="padding:6px 8px;">Faster than waterfall</td><td style="padding:6px 8px;">Unclear user requirements</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--orange);font-weight:600;">⚡ RAD</td><td style="padding:6px 8px;">✅ High</td><td style="padding:6px 8px;">Very fast</td><td style="padding:6px 8px;">Speed + working software</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--green);font-weight:600;">🧩 PDM</td><td style="padding:6px 8px;">✅ Medium-High</td><td style="padding:6px 8px;">Medium</td><td style="padding:6px 8px;">Large systems split into modules</td></tr><tr><td style="padding:6px 8px;color:var(--red);font-weight:600;">🚀 Agile</td><td style="padding:6px 8px;">✅✅ Very High</td><td style="padding:6px 8px;">Continuous (2–4 wk sprints)</td><td style="padding:6px 8px;">Changing requirements, modern teams</td></tr></tbody></table><div class="callout important">📘 The textbook focuses on <strong>PDM</strong> because it best shows where testing fits across the lifecycle. <strong>Agile</strong> is the modern industry default — covered in card 13.</div><div class="zh-note">5 种 SDLC：瀑布(僵)→原型(灵活)→RAD(快)→PDM(分模块)→Agile(冲刺)。教材重点是 PDM，现实工作中用 Agile。</div>`},
{title:"🔄 Prototyping + Online Bookstore Example",ref:"pp.31",content:`<p>Build a working model early, get feedback, refine. Repeat until users approve.</p><p><strong>📖 Scenario: Building an Online Bookstore</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:50px;">Step</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Activity</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Outcome</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--purple);">1️⃣</td><td style="padding:8px;">Build basic prototype: homepage + search + book listings</td><td style="padding:8px;font-style:italic;">Users see "is this the right shape?"</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--purple);">2️⃣</td><td style="padding:8px;">Collect feedback — users want filters, cart fixes</td><td style="padding:8px;font-style:italic;">"Reject" → loop back to fix</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--purple);">3️⃣</td><td style="padding:8px;">Iterate until approved → build full system (payment, accounts, admin)</td><td style="padding:8px;font-style:italic;">"Approve" → expand scope</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px;font-weight:700;color:var(--purple);">4️⃣</td><td style="padding:8px;"><strong>Cutover</strong> — deploy production system</td><td style="padding:8px;font-style:italic;">Live, with monitoring</td></tr></tbody></table><p><strong>Two Types of Prototype:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><tbody><tr><td style="padding:8px;background:var(--bg-warm);width:40%;"><strong>🗑️ Requirement Prototype</strong></td><td style="padding:8px;">Thrown away after gathering feedback — purpose was to UNDERSTAND requirements.</td></tr><tr><td style="padding:8px;background:var(--bg-warm);"><strong>🌱 Evolutionary Prototype</strong></td><td style="padding:8px;">Grows into the final system — code is kept and expanded.</td></tr></tbody></table><div class="callout"><strong>Advantage:</strong> Reduces risk of wrong-system development by getting feedback BEFORE big investment.</div><div class="zh-note">原型 = 先做个雏形让用户看 → 不行重做 → 行就扩展 → 上线。两类：需求型(扔掉)、进化型(变最终系统)。</div>`},
{title:"⚡ RAD: SWAT Teams + Electric E-Commerce in 4 Iterations",ref:"pp.32",content:`<p><span class="key-term">RAD</span> (Rapid Application Development) = Prototyping + Iterative + <strong>SWAT teams</strong> + <strong>CASE tools</strong>. Goal: fully functional app, fast.</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><tbody><tr><td style="padding:8px;background:var(--bg-warm);width:40%;"><strong>🥋 SWAT Team</strong></td><td style="padding:8px;"><em>"Skill With Advanced Tools"</em> — small expert team, one feature/module each</td></tr><tr><td style="padding:8px;background:var(--bg-warm);"><strong>🛠️ CASE Tools</strong></td><td style="padding:8px;"><em>"Computer-Aided Software Engineering"</em> — code generators, modeling tools to speed up dev</td></tr></tbody></table><p><strong>🛒 Scenario: Building an E-commerce App in 4 Iterations</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Iteration</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Features Released</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">User Feedback</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">1</td><td style="padding:6px 8px;">Product catalog · search · add to cart</td><td style="padding:6px 8px;font-style:italic;">"Need category filters"</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">2</td><td style="padding:6px 8px;">Filters · wishlist · better search</td><td style="padding:6px 8px;font-style:italic;">"Want product recommendations"</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">3</td><td style="padding:6px 8px;">Payment gateway · discounts</td><td style="padding:6px 8px;font-style:italic;">"More payment options please"</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">4️⃣ Final</td><td style="padding:6px 8px;">Full catalog · checkout · profiles · admin panel</td><td style="padding:6px 8px;font-style:italic;">Deployed live</td></tr></tbody></table><div class="callout"><strong>Why it works:</strong> Parallel teams + early prototypes + frequent user feedback = quality built incrementally, not at the end.</div><div class="zh-note">RAD = 原型 + 迭代 + SWAT精英小组 + CASE工具。多个小组并行做不同模块，每次迭代加新功能，用户反馈早+频繁。</div>`},
{title:"🧩 PDM: 6 Stages + Data Warehouse Parallel Modules",ref:"pp.33–57",content:`<p><span class="key-term">PDM</span> (Phased Development Methodology) = the textbook's preferred framework. Splits a big system into <strong>modules</strong>; each module is a mini SDLC.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Stage</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">What Happens</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">1</td><td style="padding:6px 8px;"><strong>Preliminary Investigation</strong></td><td style="padding:6px 8px;">Define problem, goals, risk, feasibility</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">2</td><td style="padding:6px 8px;"><strong>Analysis</strong></td><td style="padding:6px 8px;">Collect functional requirements (interviews, JAD, surveys)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">3</td><td style="padding:6px 8px;"><strong>Design</strong></td><td style="padding:6px 8px;">Logical design: UI, data, procedures, controls</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">4</td><td style="padding:6px 8px;"><strong>Preliminary Construction</strong></td><td style="padding:6px 8px;">Code modules + developer unit tests (white-box)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">5</td><td style="padding:6px 8px;"><strong>Final Construction</strong></td><td style="padding:6px 8px;">Integrate modules + test team does black-box + perf</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">6</td><td style="padding:6px 8px;"><strong>Installation</strong></td><td style="padding:6px 8px;">Deploy to production + post-impl review</td></tr></tbody></table><p><strong>🏭 Scenario: Building a Sales Data Warehouse (parallel modules)</strong></p><div style="background:var(--bg-warm);padding:14px;border-radius:8px;margin:10px 0;font-size:13.5px;border-left:3px solid var(--green);">Three modules built <strong>in parallel</strong>, then integrated:<br>🟦 <strong>Staging Area</strong> — prepare raw data &nbsp;&nbsp;➜&nbsp;&nbsp; 🟩 <strong>Warehouse</strong> — store cleaned data &nbsp;&nbsp;➜&nbsp;&nbsp; 🟧 <strong>Information Delivery</strong> — reports to users<br><br>Each module: own analysis → design → construction → tested independently → then full-system integration test.</div><div class="zh-note">PDM 6 阶段：初查→分析→设计→初构→终构→安装。把大系统拆成模块，每个模块走自己的小 SDLC，并行进行后再集成。</div>`},
{title:"🔬 Testing in PDM: 4 Phases of Testing",ref:"Module 2 + pp.16–21",content:`<p>Testing is <strong>continuous</strong> throughout PDM — not just at the end. It changes shape per stage.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Phase</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Type</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">What Gets Tested</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--blue);font-weight:600;">1️⃣ Early (Prelim Invest. + Analysis + Design)</td><td style="padding:8px;"><span class="key-term">Static</span></td><td style="padding:8px;font-style:italic;">Documents: requirements, designs, blueprints. Catch errors BEFORE coding.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--purple);font-weight:600;">2️⃣ Module Construction</td><td style="padding:8px;"><span class="key-term">Active</span></td><td style="padding:8px;font-style:italic;">Run each module's code: staging data, repository queries, info delivery screens. Iteratively + parallel.</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--orange);font-weight:600;">3️⃣ Final Construction</td><td style="padding:8px;"><span class="key-term">Integration</span></td><td style="padding:8px;font-style:italic;">All modules together. Do they communicate correctly?</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px;color:var(--green);font-weight:600;">4️⃣ Installation / Deployment</td><td style="padding:8px;"><span class="key-term">Passive</span></td><td style="padding:8px;font-style:italic;">Monitor in production. Verify continued operation. Rely on prior validations.</td></tr></tbody></table><div class="callout important"><strong>Key insight:</strong> Static testing first (cheapest!) → active per module → integration → passive monitoring. <strong>Early testing = cheaper bugs.</strong></div><div class="zh-note">PDM 测试 4 阶段：早期静态测文档 → 模块构建期主动测代码 → 终构集成测 → 部署后被动监控。越早测越省钱。</div>`},
{title:"🏢 Preliminary Investigation: Enterprise Analysis + Risk Scoring",ref:"pp.37–43",content:`<p>Stage 1 of PDM = understand the organization BEFORE designing.</p><p><strong>🔄 Closed-Loop Enterprise System</strong> — every system has these components:</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Component</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Test Type</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Standards</td><td style="padding:6px 8px;">Static</td><td style="padding:6px 8px;">Verify policies &amp; rules</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Information Processor</td><td style="padding:6px 8px;">Functional</td><td style="padding:6px 8px;">Test data calc &amp; workflows</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Input Resources</td><td style="padding:6px 8px;">Input validation</td><td style="padding:6px 8px;">Verify customer/order data</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Transformation</td><td style="padding:6px 8px;">Module / execution</td><td style="padding:6px 8px;">Test business logic</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Output Resources</td><td style="padding:6px 8px;">Output verification</td><td style="padding:6px 8px;">Check reports &amp; dashboards</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;">Environment</td><td style="padding:6px 8px;">UAT / Monitoring</td><td style="padding:6px 8px;">Real-world conditions</td></tr></tbody></table><p><strong>📊 Risk Evaluation Scoring</strong> — rate each project characteristic:</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><tbody><tr style="background:var(--green-bg);"><td style="padding:8px;font-weight:700;color:var(--green);width:60px;">+1</td><td style="padding:8px;">No risk — good condition</td></tr><tr style="background:var(--orange-bg);"><td style="padding:8px;font-weight:700;color:var(--orange);">&nbsp;0&nbsp;</td><td style="padding:8px;">Moderate / uncertain (borderline)</td></tr><tr style="background:var(--red-bg);"><td style="padding:8px;font-weight:700;color:var(--red);">−1</td><td style="padding:8px;">High risk — problem exists</td></tr></tbody></table><p>Sum all scores across 4 categories: <strong>Organization · Information System · Developers · Users</strong>. Score range:</p><table style="width:100%;border-collapse:collapse;margin:6px 0;font-size:13px;"><tbody><tr style="background:var(--green-bg);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">+8 to +15</td><td style="padding:6px 8px;">🟢 LOW risk — high success chance</td></tr><tr style="background:var(--orange-bg);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">+1 to +7</td><td style="padding:6px 8px;">🟡 MODERATE risk — some issues</td></tr><tr style="background:var(--red-bg);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">0 or below</td><td style="padding:6px 8px;">🔴 HIGH risk — may fail</td></tr></tbody></table><div class="callout">👉 Try this hands-on in the <strong>Interactive</strong> tab — Risk Calculator widget.</div><div class="zh-note">先理解企业（闭环系统）+ 评估风险（4 类打分 +1/0/-1，总分越高越安全）。试试 Interactive 标签的 Risk Calculator。</div>`},
{title:"✅ 5 Types of Feasibility (with Examples)",ref:"pp.42–43",content:`<p>Before committing budget, check 5 angles. Any one failing = redesign or kill the project.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Type</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Question</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Hospital System Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">🔧 Technical</td><td style="padding:6px 8px;">Does the tech exist?</td><td style="padding:6px 8px;font-style:italic;">IT staff + DBs + networking already in place ✅</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--green);font-weight:600;">💰 Economic</td><td style="padding:6px 8px;">Cost-effective?</td><td style="padding:6px 8px;font-style:italic;">High dev cost, but saves paper + long-term efficiency ✅</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">👥 Operational</td><td style="padding:6px 8px;">Will users use it?</td><td style="padding:6px 8px;font-style:italic;">Staff training + simple UI = workable ✅</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--orange);font-weight:600;">⚖️ Legal &amp; Ethical</td><td style="padding:6px 8px;">Within laws?</td><td style="padding:6px 8px;font-style:italic;">Follows HIPAA + healthcare privacy ✅</td></tr><tr><td style="padding:6px 8px;color:var(--red);font-weight:600;">📅 Schedule</td><td style="padding:6px 8px;">Can it ship on time?</td><td style="padding:6px 8px;font-style:italic;">6–8 months realistic with current team ✅</td></tr></tbody></table><div class="callout important">All 5 must pass. A "Technical Yes" + "Economic No" = project fails — common cause of cancellations.</div><div class="zh-note">5 种可行性：技术/经济/运营/法律/进度。任何一个不通过都要重新评估。背口诀：技经运法时。</div>`},
{title:"🗣️ JAD: Joint Application Design Sessions",ref:"pp.43",content:`<p>A <strong>structured workshop</strong> where users + developers + a neutral facilitator together confirm requirements BEFORE construction.</p><p><strong>🛒 Scenario: Online Shopping Website JAD</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;background:var(--accent-bg);width:35%;font-weight:600;color:var(--accent-dim);">Participants</td><td style="padding:8px;">Users · managers · developers · facilitator (neutral)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">Purpose</td><td style="padding:8px;">Confirm requirements BEFORE coding starts</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">Findings</td><td style="padding:8px;">Browse products · add to cart · checkout · delivery tracking</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">User Input</td><td style="padding:8px;">"Need filters" · "Fast checkout" · "Order tracking"</td></tr><tr><td style="padding:8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">Outcome</td><td style="padding:8px;"><strong>Agreed</strong> requirements + reduced rework risk</td></tr></tbody></table><div class="callout"><strong>Why it matters:</strong> Cheaper to argue in a room for 2 days than rewrite code for 2 months. Recall the <em>Gossip Game</em> from Chapter 1 — JAD prevents requirements distortion.</div><div class="zh-note">JAD = 用户+开发者+主持人坐一起把需求确认清楚再开始编码。回想第一章的"传话游戏"——JAD 就是防止需求走样。</div>`},
{title:"🔍 Analysis Stage: 5 Methods + Functional Components Matrix",ref:"pp.43–46",content:`<p>The Analysis stage <strong>collects</strong> what the system must do. Five techniques used together:</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Method</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Purpose</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📚 Existing System Study</td><td style="padding:6px 8px;">Read old reports, DFDs, screen layouts</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🎙️ Interviews</td><td style="padding:6px 8px;">Detailed needs from managers</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📊 Surveys</td><td style="padding:6px 8px;">Many users at once (questionnaires)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🗣️ JAD Sessions</td><td style="padding:6px 8px;">Group requirement finalization</td></tr><tr><td style="padding:6px 8px;font-weight:600;">👀 System Observation</td><td style="padding:6px 8px;">Watch real users in action</td></tr></tbody></table><p><strong>📐 Functional Components Matrix</strong> — output of analysis. A 4×5 table:</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12px;"><thead><tr style="background:var(--accent-bg);"><th style="padding:6px;border:1px solid var(--border-light);"></th><th style="padding:6px;border:1px solid var(--border-light);color:var(--accent-dim);">Input</th><th style="padding:6px;border:1px solid var(--border-light);color:var(--accent-dim);">Process</th><th style="padding:6px;border:1px solid var(--border-light);color:var(--accent-dim);">Output</th><th style="padding:6px;border:1px solid var(--border-light);color:var(--accent-dim);">Storage</th><th style="padding:6px;border:1px solid var(--border-light);color:var(--accent-dim);">Control</th></tr></thead><tbody><tr><td style="padding:6px;border:1px solid var(--border-light);background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">👥 People</td><td style="padding:6px;border:1px solid var(--border-light);">type</td><td style="padding:6px;border:1px solid var(--border-light);">decide</td><td style="padding:6px;border:1px solid var(--border-light);">read</td><td style="padding:6px;border:1px solid var(--border-light);">remember</td><td style="padding:6px;border:1px solid var(--border-light);">approve</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px;border:1px solid var(--border-light);background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">💾 Data</td><td style="padding:6px;border:1px solid var(--border-light);">form</td><td style="padding:6px;border:1px solid var(--border-light);">transform</td><td style="padding:6px;border:1px solid var(--border-light);">report</td><td style="padding:6px;border:1px solid var(--border-light);">DB</td><td style="padding:6px;border:1px solid var(--border-light);">audit</td></tr><tr><td style="padding:6px;border:1px solid var(--border-light);background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">💻 Software</td><td style="padding:6px;border:1px solid var(--border-light);">parse</td><td style="padding:6px;border:1px solid var(--border-light);">compute</td><td style="padding:6px;border:1px solid var(--border-light);">render</td><td style="padding:6px;border:1px solid var(--border-light);">cache</td><td style="padding:6px;border:1px solid var(--border-light);">auth</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px;border:1px solid var(--border-light);background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">🖥️ Hardware</td><td style="padding:6px;border:1px solid var(--border-light);">keyboard</td><td style="padding:6px;border:1px solid var(--border-light);">CPU</td><td style="padding:6px;border:1px solid var(--border-light);">monitor</td><td style="padding:6px;border:1px solid var(--border-light);">disk</td><td style="padding:6px;border:1px solid var(--border-light);">firewall</td></tr></tbody></table><div class="callout"><strong>Rows = resources</strong> (people, data, software, hardware). <strong>Columns = activities</strong> (input, process, output, storage, control). Every cell must be filled — forces complete thinking.</div><div class="zh-note">分析阶段 5 法：读旧系统/访谈/问卷/JAD/观察。输出：功能组件矩阵（4 资源 × 5 活动 = 20 格全要填）。</div>`},
{title:"📐 Design / Construction / Installation Stages",ref:"pp.46–57",content:`<p>The last three PDM stages — turning requirements into a running system.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Stage</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Key Activities</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);vertical-align:top;"><td style="padding:8px;color:var(--blue);font-weight:600;">📐 Design</td><td style="padding:8px;">6 logical-design components:<br>• <strong>UI</strong> (forms, buttons)<br>• <strong>Procedure</strong> (order→pay→confirm)<br>• <strong>Data</strong> (DB schema)<br>• <strong>System Interface</strong> (payment/delivery APIs)<br>• <strong>System Control</strong> (login, backup, error checks)<br>• <strong>Software</strong> (languages, tools)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);vertical-align:top;"><td style="padding:8px;color:var(--purple);font-weight:600;">🔨 Preliminary Construction</td><td style="padding:8px;">For EACH module: code → unit-test → integrate → demo to users → get approval. Loops until ready.</td></tr><tr style="vertical-align:top;"><td style="padding:8px;color:var(--green);font-weight:600;">🚀 Final Construction + Installation</td><td style="padding:8px;"><strong>Final:</strong> Integrate all modules · system test · UAT · training · final docs<br><strong>Install:</strong> Hardware + cutover + post-implementation evaluation</td></tr></tbody></table><div class="callout important"><strong>UAT = User Acceptance Testing</strong> — the final gate before "go live". If users reject it here, you go back.</div><div class="zh-note">后 3 阶段：设计(6 大组件) → 初构(逐模块编码+单测) → 终构+安装(集成+UAT+部署)。UAT 通不过就回炉。</div>`},
{title:"🚀 AGILE + Agile Testing (Modern Standard)",ref:"Module 2 add-on",content:`<p><strong>2007 book doesn't cover Agile</strong> — but it's the industry standard today. Module 2 adds it because no real software team in 2026 uses pure waterfall.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Aspect</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Agile Approach</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🏃 Sprints</td><td style="padding:6px 8px;">1–4 week cycles. Working software each cycle.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📞 Feedback</td><td style="padding:6px 8px;">Continuous from customer — change requests welcomed</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📦 Delivery</td><td style="padding:6px 8px;">Early + frequent — not "big bang"</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">🧪 Testing</td><td style="padding:6px 8px;">In every sprint. Devs + testers + users together.</td></tr></tbody></table><p><strong>🛒 Scenario: E-commerce app in 4 sprints</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Sprint</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Built</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Tested in same sprint</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">1</td><td style="padding:6px 8px;">Product listing + search</td><td style="padding:6px 8px;font-style:italic;">Search results accuracy</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">2</td><td style="padding:6px 8px;">Cart + wishlist</td><td style="padding:6px 8px;font-style:italic;">Add/remove cart functions</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">3</td><td style="padding:6px 8px;">Payment integration</td><td style="padding:6px 8px;font-style:italic;">Payment success/failure</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">4</td><td style="padding:6px 8px;">Order tracking</td><td style="padding:6px 8px;font-style:italic;">Tracking updates</td></tr></tbody></table><p><strong>🧪 Agile Testing Principles:</strong></p><div style="background:var(--bg-warm);padding:14px;border-radius:8px;border-left:3px solid var(--red);margin:10px 0;font-size:13.5px;"><strong>Test early · Test often · Fix immediately</strong><br>Bugs found in Sprint 2 are fixed in Sprint 2 — not Sprint 8. Defect cost stays low.</div><div class="callout important"><strong>Compare:</strong> Waterfall = test once, at the end (expensive bugs). Agile = test in every sprint (cheap bugs). Modern teams pick Agile by default.</div><div class="zh-note">🚀 Agile = 短周期冲刺(1-4周) + 每个冲刺都交付可用软件 + 边开发边测试。比瀑布灵活多了，是现代标配。试试 Interactive 标签的 Sprint 动画。</div>`}
],quiz:[
{type:"mc",q:"A 'methodology' is best described as:",options:["A software application","A recommended way of doing something","An automated testing tool","A programming language"],answer:1,explanation:"Methodology = 'a recommended way of doing something.' Like an architect's blueprint."},
{type:"mc",q:"Which SDLC is best when user requirements are UNCLEAR?",options:["Waterfall","Prototyping","PDM","All work equally well"],answer:1,explanation:"Prototyping is designed for unclear requirements — build a model, get feedback, iterate."},
{type:"mc",q:"In RAD, 'SWAT' stands for:",options:["System Wide Application Test","Skill With Advanced Tools","Software Workflow Analysis Team","Standardized Web Application Toolkit"],answer:1,explanation:"SWAT = Skill With Advanced Tools — small expert teams that work fast with CASE tools."},
{type:"mc",q:"In the data warehouse PDM example, which 3 modules are built in parallel?",options:["Staging · Warehouse · Information Delivery","Frontend · Backend · Database","UI · API · DevOps","Plan · Build · Test"],answer:0,explanation:"Staging (raw data prep) · Warehouse (clean storage) · Information Delivery (reports). Three parallel modules, then integrated."},
{type:"sa",q:"List the 6 stages of PDM in order.",sampleAnswer:"1. Preliminary Investigation\n2. Analysis\n3. Design\n4. Preliminary Construction\n5. Final Construction\n6. Installation",keywords:["preliminary investigation","analysis","design","preliminary construction","final construction","installation"]},
{type:"mc",q:"Static testing in PDM happens during which phase(s)?",options:["Only during Installation","Only during Preliminary Construction","Early phases — Preliminary Investigation, Analysis, Design","Only after deployment"],answer:2,explanation:"Static testing reviews DOCUMENTS — done early (Prelim Investigation, Analysis, Design) before code exists. Cheapest defect-removal stage."},
{type:"mc",q:"On the risk-evaluation scoring sheet, what does +1 mean?",options:["High risk — problem exists","Moderate / borderline","No risk — good condition","Score is undefined"],answer:2,explanation:"+1 = no risk. 0 = moderate. −1 = high risk. Sum across 4 categories to get total."},
{type:"mc",q:"'Is the system workable given people's skills?' refers to which feasibility?",options:["Technical","Economic","Operational","Schedule"],answer:2,explanation:"Operational feasibility evaluates whether people can actually make the system work in practice."},
{type:"mc",q:"What is a JAD session?",options:["Developer-only code review","Joint meeting of users + developers + facilitator to confirm requirements","Automated test tool session","Post-implementation review"],answer:1,explanation:"JAD = Joint Application Design — users, developers, managers meet with a neutral facilitator BEFORE coding starts."},
{type:"sa",q:"Name all 5 types of feasibility studies.",sampleAnswer:"Technical, Economic, Operational, Legal & Ethical, and Schedule feasibility.",keywords:["technical","economic","operational","legal","schedule"]},
{type:"mc",q:"In the Functional Components Matrix, ROWS represent:",options:["Activities (Input, Process, Output, Storage, Control)","Resources (People, Data, Software, Hardware)","Time phases","Risk levels"],answer:1,explanation:"Rows = resources (People, Data, Software, Hardware). Columns = activities (Input, Process, Output, Storage, Control). 4×5 grid forces complete coverage."},
{type:"mc",q:"A typical Agile sprint length is:",options:["1 day","1–4 weeks","6 months","1 year"],answer:1,explanation:"Sprints are 1–4 weeks. Each delivers working software that can be tested and shown to users."},
{type:"sa",q:"What is the key philosophy of Agile testing? When does testing happen?",sampleAnswer:"Test early, test often, fix immediately. Testing happens continuously DURING each sprint — not only at the end. Developers, testers, and users collaborate. Bugs found in a sprint are fixed in the same sprint, preventing accumulation.",keywords:["early","often","fix immediately","sprint","continuous","collaboration"]},
{type:"mc",q:"What is the main difference between Waterfall and Agile?",options:["Waterfall uses tools; Agile doesn't","Waterfall tests once at the end; Agile tests every sprint","Waterfall is faster than Agile","There is no difference"],answer:1,explanation:"Waterfall = sequential, test at end (expensive bugs). Agile = iterative, test every sprint (cheap bugs caught early)."},
{type:"sa",q:"What is the difference between a 'requirement prototype' and an 'evolutionary prototype'?",sampleAnswer:"Requirement prototype is THROWN AWAY after gathering feedback — its only purpose was to UNDERSTAND what users need. Evolutionary prototype GROWS INTO the final system — the code is kept and expanded with each iteration. Both reduce risk, but in different ways: one explores requirements, the other delivers the product.",keywords:["requirement","thrown away","evolutionary","grows","final system","feedback","understand"]},
{type:"mc",q:"In RAD, 'CASE tools' stands for:",options:["Computer-Aided Software Engineering","Continuous Application Software Environment","Customer Approval and System Evaluation","Coded Application Speed Enhancement"],answer:0,explanation:"CASE = Computer-Aided Software Engineering. Tools like code generators, modeling tools, and design environments that speed up development."},
{type:"mc",q:"A project's risk scorecard sums to +3 across all 4 categories. The project is rated:",options:["LOW risk — very stable","MODERATE risk — some issues remain","HIGH risk — likely to fail","Undefined — needs re-scoring"],answer:1,explanation:"Score ranges: +8 to +15 = LOW · +1 to +7 = MODERATE · 0 or below = HIGH. A +3 sits in MODERATE — the project can proceed but with risk-mitigation strategies (training, prototyping, better planning)."},
{type:"mc",q:"In the Functional Components Matrix, the items 'Input', 'Process', 'Output', 'Storage', and 'Control' are:",options:["The rows (resources)","The columns (activities)","Test phases","Risk categories"],answer:1,explanation:"Rows = resources (People, Data, Software, Hardware). Columns = activities (Input, Process, Output, Storage, Control). The 4×5 = 20 cells force complete coverage of who-does-what."},
{type:"mc",q:"UAT (User Acceptance Testing) happens during which PDM stage?",options:["Preliminary Investigation","Analysis","Final Construction","Post-implementation only"],answer:2,explanation:"UAT happens in Final Construction — users formally APPROVE the system ('go live' gate) before deployment. If UAT fails, you loop back to fix; you don't push forward."},
{type:"mc",q:"SCENARIO: A medical-device firmware project — strict FDA regulations, requirements fixed by law, 24-month fixed scope. Best SDLC?",options:["Waterfall","Prototyping","RAD","Agile"],answer:0,explanation:"Regulated industries (medical, aerospace, defense, banking) often MANDATE Waterfall because the audit trail + fixed-scope contracts match its structured stages. Agile's 'changing requirements' philosophy clashes with 'FDA-mandated requirements cannot change.'"},
{type:"mc",q:"SCENARIO: A fitness mobile-app startup — requirements change weekly based on A/B tests, must ship features fast. Best SDLC?",options:["Waterfall","PDM","Agile","Pure Prototyping"],answer:2,explanation:"Agile is built for changing requirements + fast continuous delivery + user feedback loops. Modern startups almost always pick Agile (Scrum or Kanban) for exactly this scenario."},
{type:"sa",q:"In Agile, if a bug is found during Sprint 3, when is it fixed? Why is this better than Waterfall?",sampleAnswer:"In Agile, bugs found in Sprint 3 are fixed in Sprint 3 — before the sprint ends. This prevents bug accumulation and keeps defect cost low (Boehm's Rule from Chapter 1). In Waterfall, all bugs from all stages surface in the final testing phase, when fixing requires redoing requirements/design/code work that's months old. Agile catches bugs while context is still fresh and the affected code is still small — cheaper and faster.",keywords:["same sprint","fix immediately","accumulate","Boehm","early","cheaper","fresh","small","context"]}
]});

// ============================================================
INTERACTIVES[2] = function(el) {
  let currentTab = 0;
  const tabs = [
    {key:'sdlc', icon:'📊', label:'SDLC Comparator'},
    {key:'risk', icon:'📈', label:'Risk Calculator'},
    {key:'sprint', icon:'🚀', label:'Agile Sprint Animator'}
  ];

  // ---------- Widget 1: SDLC Comparator ----------
  const sdlcs = [
    {key:'waterfall',name:'Waterfall',color:'#4a7fb5',icon:'🌊',
      flow:['Planning','Analysis','Design','Implementation','Testing','Deploy'],
      good:['Stable, well-known requirements','Government / regulated industries','Long-term projects with fixed scope'],
      bad:['Cannot adapt to changes','Testing only at end → expensive bugs','No working software until very late'],
      flex:'⛔ Very Low',time:'Months to years',testing:'Once, at the end (expensive bugs)'},
    {key:'proto',name:'Prototyping',color:'#7c6baf',icon:'🔄',
      flow:['Build prototype','User feedback','Reject/Approve','Refine','Build full','Deploy'],
      good:['Unclear user requirements','UI-heavy projects','Want to validate ideas fast'],
      bad:['Throwaway code wastes effort if not managed','Users may confuse prototype with final','Hard to estimate cost'],
      flex:'✅ High',time:'Faster than waterfall',testing:'After each prototype refinement'},
    {key:'rad',name:'RAD',color:'#c08530',icon:'⚡',
      flow:['Quick requirements','SWAT team coding','User feedback','Iterate','Cutover'],
      good:['Need speed + working software','Small to medium projects','Strong user availability'],
      bad:['Needs skilled SWAT teams (rare)','Not for large enterprise systems','Heavy user time commitment'],
      flex:'✅ High',time:'Very fast (weeks)',testing:'Continuous, integrated with coding'},
    {key:'pdm',name:'PDM',color:'#3d8b5a',icon:'🧩',
      flow:['Prelim Invest','Analysis','Design','Prelim Constr','Final Constr','Install'],
      good:['Large systems splittable into modules','Parallel team work','Best for learning testing concepts (book!)'],
      bad:['Module integration can be tricky','Not the fastest','Needs strong project management'],
      flex:'✅ Medium-High',time:'Medium',testing:'4 phases: static→active→integration→passive'},
    {key:'agile',name:'Agile',color:'#c25450',icon:'🚀',
      flow:['Sprint plan','Code+Test','Demo','Retrospective','Repeat'],
      good:['Changing requirements','Modern web/mobile apps','Continuous user feedback'],
      bad:['Hard for fixed-scope contracts','Needs disciplined team','Documentation often suffers'],
      flex:'✅✅ Very High',time:'Continuous (2–4 wk sprints)',testing:'Every sprint, devs+testers+users together'}
  ];
  let sdlcSel = 0;

  function renderSdlc() {
    const s = sdlcs[sdlcSel];
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Click each SDLC to compare its flow, strengths, and weaknesses.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:16px;flex-wrap:wrap;">';
    sdlcs.forEach((x,i)=>{
      const active=i===sdlcSel;
      h += `<div onclick="window._u2sdlc(${i})" style="cursor:pointer;flex:1;min-width:100px;padding:12px 8px;border-radius:10px;text-align:center;font-size:12.5px;font-weight:600;border:2px solid ${active?x.color:'transparent'};background:${active?'var(--bg-warm)':'var(--surface2)'};color:var(--text);transition:all .2s;transform:${active?'translateY(-2px)':'none'};box-shadow:${active?'0 4px 12px rgba(0,0,0,0.08)':'none'};">`;
      h += `<div style="font-size:22px;margin-bottom:4px;">${x.icon}</div>`;
      h += `<div style="color:${x.color};">${x.name}</div></div>`;
    });
    h += '</div>';
    h += `<div style="background:var(--surface);border:2px solid ${s.color};border-radius:12px;padding:18px 20px;box-shadow:0 2px 8px rgba(0,0,0,0.05);transition:all .3s;">`;
    h += `<div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;"><span style="font-size:28px;">${s.icon}</span><div><div style="font-size:18px;font-weight:700;color:${s.color};">${s.name}</div><div style="font-size:11px;color:var(--text-dim);">Flexibility: ${s.flex} · Timeline: ${s.time}</div></div></div>`;
    // Animated flow
    h += '<div style="display:flex;align-items:center;gap:4px;flex-wrap:wrap;margin-bottom:14px;padding:10px;background:var(--bg-warm);border-radius:8px;">';
    s.flow.forEach((step,i)=>{
      h += `<div style="background:${s.color};color:#fff;padding:6px 10px;border-radius:6px;font-size:11.5px;font-weight:600;animation:u2fade ${0.3 + i*0.1}s ease-out;">${step}</div>`;
      if(i < s.flow.length-1) h += `<span style="color:${s.color};font-weight:700;">→</span>`;
    });
    h += '</div>';
    h += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:10px;">`;
    h += `<div style="background:var(--green-bg);border-radius:8px;padding:10px 12px;"><div style="font-size:12px;font-weight:700;color:var(--green);margin-bottom:6px;">✅ Best for</div>`;
    s.good.forEach(g => { h += `<div style="font-size:12px;margin-bottom:3px;color:var(--text);">• ${g}</div>`; });
    h += `</div>`;
    h += `<div style="background:var(--red-bg);border-radius:8px;padding:10px 12px;"><div style="font-size:12px;font-weight:700;color:var(--red);margin-bottom:6px;">⚠️ Watch out</div>`;
    s.bad.forEach(b => { h += `<div style="font-size:12px;margin-bottom:3px;color:var(--text);">• ${b}</div>`; });
    h += `</div></div>`;
    h += `<div style="background:var(--accent-bg);border-radius:8px;padding:10px 12px;font-size:12.5px;"><strong style="color:var(--accent-dim);">🧪 Testing approach:</strong> ${s.testing}</div>`;
    h += '</div>';
    h += '<style>@keyframes u2fade{from{opacity:0;transform:translateX(-10px);}to{opacity:1;transform:translateX(0);}}</style>';
    return h;
  }
  window._u2sdlc = function(i){ sdlcSel=i; rerender(); };

  // ---------- Widget 2: Risk Calculator ----------
  const riskItems = [
    {cat:'Organization',item:'Well-defined objectives?'},
    {cat:'Organization',item:'Guided by strategic IS plan?'},
    {cat:'Organization',item:'Supports organizational objectives?'},
    {cat:'Information System',item:'Existing system documented?'},
    {cat:'Information System',item:'Automates routine procedures?'},
    {cat:'Information System',item:'Single business area only?'},
    {cat:'Information System',item:'Uses proven technology?'},
    {cat:'Information System',item:'Implementable in 3 months?'},
    {cat:'Developers',item:'Developers experienced?'},
    {cat:'Developers',item:'Skilled in requirements analysis?'},
    {cat:'Developers',item:'Familiar with IT tools?'},
    {cat:'Users',item:'Users have business experience?'},
    {cat:'Users',item:'Users committed to project?'}
  ];
  let riskScores = riskItems.map(()=>0);

  function renderRisk() {
    const total = riskScores.reduce((a,b)=>a+b,0);
    let level, color, bg, label;
    if (total >= 8) { level='LOW'; color='var(--green)'; bg='var(--green-bg)'; label='🟢 Very stable, high success chance'; }
    else if (total >= 1) { level='MODERATE'; color='var(--orange)'; bg='var(--orange-bg)'; label='🟡 Generally okay, some risks remain'; }
    else { level='HIGH'; color='var(--red)'; bg='var(--red-bg)'; label='🔴 Many issues — project may fail'; }
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Score each item: <strong style="color:var(--green);">+1</strong> = no risk · <strong style="color:var(--orange);">0</strong> = borderline · <strong style="color:var(--red);">−1</strong> = high risk. Score updates live below.</p>';
    let lastCat = '';
    h += '<div style="background:var(--surface);border-radius:10px;overflow:hidden;border:1px solid var(--border-light);">';
    riskItems.forEach((r,i) => {
      if (r.cat !== lastCat) {
        h += `<div style="background:var(--accent-bg);padding:8px 14px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--accent-dim);border-top:${lastCat?'1px solid var(--border-light)':'none'};">${r.cat}</div>`;
        lastCat = r.cat;
      }
      const v = riskScores[i];
      h += `<div style="display:flex;align-items:center;padding:8px 14px;font-size:13px;border-top:1px solid var(--border-light);"><div style="flex:1;color:var(--text);">${r.item}</div><div style="display:flex;gap:4px;">`;
      [[+1,'+1','var(--green)','var(--green-bg)'],[0,'0','var(--orange)','var(--orange-bg)'],[-1,'−1','var(--red)','var(--red-bg)']].forEach(([val,lbl,col,bgC])=>{
        const sel=v===val;
        h += `<button onclick="window._u2risk(${i},${val})" style="cursor:pointer;width:32px;height:28px;border-radius:6px;border:2px solid ${sel?col:'var(--border-light)'};background:${sel?bgC:'var(--surface)'};color:${sel?col:'var(--text-dim)'};font-weight:700;font-size:13px;transition:all .15s;">${lbl}</button>`;
      });
      h += `</div></div>`;
    });
    h += '</div>';
    h += `<div style="margin-top:16px;padding:16px 20px;border-radius:12px;background:${bg};border:2px solid ${color};display:flex;align-items:center;justify-content:space-between;transition:all .3s;">`;
    h += `<div><div style="font-size:11px;color:var(--text-dim);text-transform:uppercase;letter-spacing:1px;font-weight:700;">Total Score</div><div style="font-size:32px;font-weight:700;color:${color};">${total >= 0 ? '+' : ''}${total}</div></div>`;
    h += `<div style="text-align:right;"><div style="font-size:18px;font-weight:700;color:${color};">${level} RISK</div><div style="font-size:12px;color:var(--text);">${label}</div></div>`;
    h += '</div>';
    h += `<button onclick="window._u2riskReset()" style="margin-top:10px;cursor:pointer;padding:6px 14px;border-radius:6px;border:1px solid var(--border);background:var(--surface);color:var(--text-dim);font-size:12px;">🔄 Reset all</button>`;
    return h;
  }
  window._u2risk = function(i,v){ riskScores[i]=v; rerender(); };
  window._u2riskReset = function(){ riskScores = riskItems.map(()=>0); rerender(); };

  // ---------- Widget 3: Agile Sprint Animator ----------
  const sprints = [
    {n:1,built:'Product listing + search',tested:'Search results accuracy',color:'#4a7fb5'},
    {n:2,built:'Cart + wishlist',tested:'Add/remove cart functions',color:'#7c6baf'},
    {n:3,built:'Payment integration',tested:'Payment success/failure',color:'#c08530'},
    {n:4,built:'Order tracking',tested:'Tracking updates',color:'#3d8b5a'}
  ];
  let sprintAnim = -1;
  let sprintTimer = null;

  function renderSprint() {
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Watch an Agile e-commerce app build over 4 sprints. Each sprint = 2-week cycle of build + test + ship.</p>';
    h += '<div style="display:flex;gap:10px;margin-bottom:14px;">';
    h += `<button onclick="window._u2play()" ${sprintAnim>=0?'disabled':''} style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:var(--accent);color:#fff;font-weight:600;font-size:13px;opacity:${sprintAnim>=0?0.5:1};">▶️ Play Animation</button>`;
    h += `<button onclick="window._u2reset()" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:13px;">🔁 Reset</button>`;
    h += '</div>';
    h += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:14px;">';
    sprints.forEach((s,i) => {
      const visible = i <= sprintAnim;
      const active = i === sprintAnim;
      h += `<div style="background:var(--surface);border:2px solid ${visible?s.color:'var(--border-light)'};border-radius:10px;padding:14px 12px;opacity:${visible?1:0.3};transform:${active?'scale(1.04)':'scale(1)'};transition:all .5s;box-shadow:${active?`0 6px 16px ${s.color}40`:'none'};">`;
      h += `<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:${s.color};margin-bottom:8px;">SPRINT ${s.n}</div>`;
      h += `<div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:8px;">🔨 ${s.built}</div>`;
      h += `<div style="font-size:12px;color:var(--text-dim);padding-top:8px;border-top:1px dashed var(--border-light);">🧪 ${s.tested}</div>`;
      if (visible) h += `<div style="margin-top:8px;font-size:10px;color:var(--green);font-weight:700;">✅ SHIPPED</div>`;
      h += `</div>`;
    });
    h += '</div>';
    // Cumulative product visualization
    h += `<div style="background:var(--bg-warm);border-radius:10px;padding:14px 18px;border-left:4px solid var(--accent);"><div style="font-size:12px;color:var(--text-dim);margin-bottom:6px;font-weight:700;text-transform:uppercase;letter-spacing:1px;">🛒 Cumulative Product after Sprint ${Math.max(0,sprintAnim+1)}</div>`;
    if (sprintAnim < 0) h += '<div style="font-size:14px;color:var(--text-light);font-style:italic;">Nothing built yet — press Play</div>';
    else {
      h += '<div style="display:flex;flex-wrap:wrap;gap:6px;">';
      sprints.slice(0,sprintAnim+1).forEach(s=>{
        h += `<span style="background:${s.color};color:#fff;padding:4px 10px;border-radius:14px;font-size:12px;font-weight:600;">${s.built}</span>`;
      });
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="margin-top:12px;padding:12px 16px;background:var(--accent-bg);border-radius:8px;font-size:12.5px;color:var(--text);"><strong>💡 Agile insight:</strong> By Sprint 1, users already have working software. By Sprint 4, you have a real e-commerce app. Each sprint can be released to production.</div>';
    return h;
  }
  window._u2play = function(){
    if (sprintTimer) clearInterval(sprintTimer);
    sprintAnim = -1;
    rerender();
    sprintTimer = setInterval(()=>{
      sprintAnim++;
      if (sprintAnim >= sprints.length) { clearInterval(sprintTimer); sprintTimer=null; sprintAnim = sprints.length-1; }
      rerender();
    }, 900);
  };
  window._u2reset = function(){
    if (sprintTimer) { clearInterval(sprintTimer); sprintTimer=null; }
    sprintAnim = -1;
    rerender();
  };

  // ---------- Main render with tabs ----------
  function rerender() {
    let h = '<div style="display:flex;gap:2px;margin-bottom:18px;background:var(--surface2);padding:3px;border-radius:10px;width:fit-content;border:1px solid var(--border-light);">';
    tabs.forEach((t,i)=>{
      const active = i===currentTab;
      h += `<button onclick="window._u2tab(${i})" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:${active?'var(--accent)':'transparent'};color:${active?'#fff':'var(--text-dim)'};font-size:13px;font-weight:600;transition:all .15s;">${t.icon} ${t.label}</button>`;
    });
    h += '</div>';
    h += '<div style="animation:u2fade 0.3s ease-out;">';
    if (currentTab===0) h += renderSdlc();
    else if (currentTab===1) h += renderRisk();
    else h += renderSprint();
    h += '</div>';
    el.innerHTML = h;
  }
  window._u2tab = function(i){
    if (sprintTimer) { clearInterval(sprintTimer); sprintTimer=null; }
    currentTab=i; rerender();
  };
  rerender();
};

// ============================================================
// Unit 2: SDLC
// (Indices match the 13-card layout: 0=Learning Obj, 1=Methodology vs Tools,
//  2=5 SDLCs, 3=Prototyping, 4=RAD, 5=PDM, 6=Testing in PDM,
//  7=Prelim Invest+Risk, 8=Feasibility, 9=JAD, 10=Analysis,
//  11=Design/Constr/Install, 12=AGILE)
// ============================================================
MODERN_NOTES['2-2'] = {
  title: 'Agile dominates — but knowing all 5 SDLCs is still tested',
  year: '2026',
  content: 'In real industry surveys (State of Agile 2025), <strong>71% of teams use Agile/Scrum</strong>, 13% use Kanban, 8% use hybrid (Agile + Waterfall), and pure Waterfall is &lt;3%. Yet ISTQB exams + most CS programs still ask about all 5 because: (1) regulated industries (medical, aerospace, defense) still mandate Waterfall, (2) understanding the evolution helps you justify Agile choices. The textbook focuses on PDM as a teaching scaffold — Agile is what you\'ll actually use at work.'
};
MODERN_NOTES['2-3'] = {
  title: 'Modern prototyping = Figma + AI mockups',
  year: '2026',
  content: 'The 2007 "build a working prototype" has split into two: (1) <strong>Figma / Penpot</strong> — clickable design prototypes built in hours, tested with users, then handed to devs. (2) <strong>MVP (Minimum Viable Product)</strong> — Eric Ries\' "Lean Startup" approach, ship the smallest real product to real users. New 2024 tools: <strong>Vercel v0, Anthropic Claude Artifacts, Lovable.dev</strong> generate working React prototypes from text prompts in minutes — the bookstore example would take 30 minutes instead of 30 days.'
};
MODERN_NOTES['2-4'] = {
  title: 'RAD lives on as low-code / no-code platforms',
  year: '2026',
  content: 'The "CASE tools" of 2007 became today\'s <strong>low-code platforms</strong>: <strong>Bubble</strong> (visual web apps), <strong>Retool</strong> (internal tools), <strong>n8n / Zapier</strong> (workflow automation), <strong>Microsoft Power Apps</strong>. A small "SWAT team" can now ship a working internal CRM in days. Gartner predicts 70% of new business apps will use low-code by 2026. Trade-off: blazing speed but lock-in to platform pricing.'
};
MODERN_NOTES['2-5'] = {
  title: 'PDM parallel modules = modern microservices',
  year: '2026',
  content: 'The textbook\'s "split into parallel modules" approach evolved into <strong>microservices architecture</strong>: each module = a separately deployable service (Docker container) with its own DB, API, and team. Examples: Netflix runs 1,000+ microservices; Uber 2,200+. Modern integration testing happens via <strong>contract testing</strong> (Pact) and <strong>service mesh</strong> tools (Istio, Linkerd). The textbook\'s "module → integration" pattern is exactly how microservices systems are tested today.'
};
MODERN_NOTES['2-6'] = {
  title: 'CI/CD replaces phase-gated testing',
  year: '2026',
  content: 'The book\'s 4 testing phases (static → active → integration → passive) now run <strong>on every code commit</strong> via CI/CD pipelines: <strong>GitHub Actions, GitLab CI, Jenkins, CircleCI</strong>. A typical pipeline: lint (static) → unit tests (active per module) → integration tests → deploy to staging → smoke tests → deploy to prod → monitoring (passive). The phases didn\'t disappear — they got automated and run thousands of times per day instead of once per release.'
};
MODERN_NOTES['2-7'] = {
  title: 'AI-assisted risk analysis is replacing manual scorecards',
  year: '2026',
  content: 'The +1/0/−1 manual scoring still works, but modern teams use AI tools like <strong>Atlassian Intelligence</strong> (in Jira) or <strong>GitHub Copilot Risk Analysis</strong> to scan project plans and flag risk patterns automatically. Healthcare/finance still require manual scorecards for compliance audits (HIPAA, SOX). The skill of breaking risk into categories (Org / IS / Devs / Users) is timeless — the tool just got smarter.'
};
MODERN_NOTES['2-9'] = {
  title: 'JAD sessions evolved into Discovery workshops & Design sprints',
  year: '2026',
  content: 'JAD\'s modern descendants: <strong>Google Design Sprints</strong> (5-day intensive process from problem → tested prototype), <strong>Discovery workshops</strong> in product management, <strong>Event Storming</strong> (DDD technique to map domain events). Tools that replaced flip charts: <strong>Miro, FigJam, Mural</strong> (collaborative whiteboards). Pandemic-era shift: most workshops are now hybrid (in-person + remote) which actually expanded participation.'
};
MODERN_NOTES['2-12'] = {
  title: 'Agile at scale: SAFe, Spotify model, Shape Up',
  year: '2026',
  content: 'Pure Scrum works for small teams. At enterprise scale, three frameworks dominate: <strong>SAFe (Scaled Agile Framework)</strong> — used at JPMorgan, Cisco; structured but heavy. <strong>Spotify Model</strong> — squads, tribes, chapters, guilds; flexible but needs strong culture. <strong>Shape Up</strong> (Basecamp/37signals) — 6-week cycles instead of 2-week sprints, more design upfront. Modern testing in Agile uses <strong>BDD (Cucumber)</strong>, <strong>TDD</strong>, and <strong>contract testing</strong> as defaults. Reality check: many companies say they\'re "Agile" but practice <strong>Waterfall-in-Sprints</strong> — the 2-week ceremony without the cultural mindset.'
};
